static void foobar(int *A, int N) {
  int B[100];
  for (int i = 0; i < 100; ++i) {
    B[i] = i + N;
  }
  if (N-- > 0)
    foobar(B, N);
  for (int i = 0; i < 100; ++i) {
    A[i] += B[i];
  }
}

static void bar(int *A, int N) {
  foobar(A, N);
}

int main(void) {
  int A[100] = {0};
  foobar(A, 4);
  bar(A, 3);
  foobar(A, 5);
  foobar(A, 2);
}

